registerModule('Movement Trail', function(g) {
  g._trail = g._trail || {
    points: [],
    maxLength: 48,
    lastX: g.px,
    lastY: g.py
  };

  var trail = g._trail;
  var ctx = g.ctx;
  var dx = g.px - trail.lastX;
  var dy = g.py - trail.lastY;
  var moved = dx * dx + dy * dy > 0.1;

  if (moved) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLength) {
      trail.points.shift();
    }
    trail.lastX = g.px;
    trail.lastY = g.py;
  }

  var len = trail.points.length;
  if (len < 2) return;

  for (var i = 1; i < len; i++) {
    var pt = trail.points[i];
    var prev = trail.points[i - 1];
    var t = i / len;
    var alpha = t * t * 0.85;
    var width = t * 3.5;

    // Color shifts from cyan-green to electric blue as trail ages
    var r = Math.round(g.lerp(0, 0, t));
    var gr = Math.round(g.lerp(80, 255, t));
    var b = Math.round(g.lerp(255, 170, t));

    ctx.beginPath();
    ctx.moveTo(prev.x, prev.y);
    ctx.lineTo(pt.x, pt.y);
    ctx.strokeStyle = 'rgba(' + r + ',' + gr + ',' + b + ',' + alpha + ')';
    ctx.lineWidth = width;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.stroke();
  }

  // Glow pulse at the tail origin
  if (len > 4) {
    var tail = trail.points[0];
    var pulse = 0.3 + 0.2 * Math.sin(g.tick * 0.18);
    var grad = ctx.createRadialGradient(tail.x, tail.y, 0, tail.x, tail.y, 5);
    grad.addColorStop(0, 'rgba(0,180,255,' + pulse + ')');
    grad.addColorStop(1, 'rgba(0,0,80,0)');
    ctx.beginPath();
    ctx.arc(tail.x, tail.y, 5, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();
  }
})

registerModule('Ambient Starfield', function(g) {
  g._stars = g._stars || (function() {
    var arr = [];
    for (var i = 0; i < 180; i++) {
      arr.push({
        x: Math.random() * 1600 - 800,
        y: Math.random() * 1200 - 600,
        z: Math.random() * 3 + 0.2,
        blink: Math.random() * Math.PI * 2,
        blinkSpeed: Math.random() * 0.04 + 0.005,
        size: Math.random() * 1.2 + 0.2,
        hue: Math.random() < 0.15 ? (Math.random() < 0.5 ? 200 : 280) : 0,
        sat: Math.random() < 0.15 ? 80 : 0
      });
    }
    return arr;
  })();

  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var cx = W / 2;
  var cy = H / 2;
  var stars = g._stars;

  ctx.save();

  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    // Parallax drift relative to player
    var wx = cx + s.x - g.px * (s.z * 0.04);
    var wy = cy + s.y - g.py * (s.z * 0.04);

    // Wrap around screen edges with some margin
    var margin = 60;
    if (wx < -margin) { s.x += W + margin * 2; }
    else if (wx > W + margin) { s.x -= W + margin * 2; }
    if (wy < -margin) { s.y += H + margin * 2; }
    else if (wy > H + margin) { s.y -= H + margin * 2; }

    // Slow twinkle
    s.blink += s.blinkSpeed;
    var alpha = 0.35 + 0.55 * (0.5 + 0.5 * Math.sin(s.blink));

    // Depth-based brightness
    var brightness = 60 + s.z * 25;
    var color;
    if (s.sat > 0) {
      color = 'hsla(' + s.hue + ',' + s.sat + '%,' + brightness + '%,' + alpha.toFixed(2) + ')';
    } else {
      var c = Math.round(brightness * 2.4);
      color = 'rgba(' + c + ',' + c + ',' + (c + 10) + ',' + alpha.toFixed(2) + ')';
    }

    var sz = s.size * (0.5 + s.z * 0.35);

    ctx.globalAlpha = 1;
    ctx.fillStyle = color;

    if (sz > 1.4) {
      // Larger stars get a soft glow
      var grd = ctx.createRadialGradient(wx, wy, 0, wx, wy, sz * 3.5);
      var glowColor = s.sat > 0
        ? 'hsla(' + s.hue + ',' + s.sat + '%,' + brightness + '%,'
        : 'rgba(' + Math.round(brightness*2.4) + ',' + Math.round(brightness*2.4) + ',' + Math.round(brightness*2.4+10) + ',';
      grd.addColorStop(0, glowColor + (alpha * 0.9).toFixed(2) + ')');
      grd.addColorStop(0.4, glowColor + (alpha * 0.25).toFixed(2) + ')');
      grd.addColorStop(1, glowColor + '0)');
      ctx.fillStyle = grd;
      ctx.beginPath();
      ctx.arc(wx, wy, sz * 3.5, 0, Math.PI * 2);
      ctx.fill();
    }

    // Core star dot
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(wx, wy, sz, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.restore();
})

registerModule('Pixel Glow Effect', function(g) {
  g._glow = g._glow || { pulse: 0, trails: [] };

  var glow = g._glow;
  var ctx = g.ctx;

  // Advance pulse oscillator
  glow.pulse = (glow.pulse + 0.05) % (Math.PI * 2);

  // Store trail positions (ring buffer style)
  if (g.tick % 2 === 0) {
    glow.trails.push({ x: g.px, y: g.py, age: 0 });
    if (glow.trails.length > 12) glow.trails.shift();
  }

  // Draw motion trails
  for (var i = 0; i < glow.trails.length; i++) {
    var t = glow.trails[i];
    t.age++;
    var trailAlpha = Math.max(0, 0.35 - t.age * 0.03);
    var trailSize = Math.max(0, 6 - t.age * 0.4);
    if (trailAlpha <= 0 || trailSize <= 0) continue;

    var trailGrad = ctx.createRadialGradient(t.x, t.y, 0, t.x, t.y, trailSize);
    trailGrad.addColorStop(0, 'rgba(0,255,170,' + trailAlpha + ')');
    trailGrad.addColorStop(1, 'rgba(0,255,170,0)');
    ctx.beginPath();
    ctx.arc(t.x, t.y, trailSize, 0, Math.PI * 2);
    ctx.fillStyle = trailGrad;
    ctx.fill();
  }

  // Pulsing outer glow radius
  var pulseVal = 0.5 + 0.5 * Math.sin(glow.pulse);
  var glowRadius = 18 + pulseVal * 8;
  var glowAlpha  = 0.18 + pulseVal * 0.12;

  // Outer ambient glow
  var outerGrad = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, glowRadius);
  outerGrad.addColorStop(0,   'rgba(0,255,170,' + (glowAlpha * 1.8).toFixed(3) + ')');
  outerGrad.addColorStop(0.4, 'rgba(0,220,150,' + glowAlpha.toFixed(3) + ')');
  outerGrad.addColorStop(1,   'rgba(0,255,170,0)');

  ctx.beginPath();
  ctx.arc(g.px, g.py, glowRadius, 0, Math.PI * 2);
  ctx.fillStyle = outerGrad;
  ctx.fill();

  // Inner bright core halo
  var coreRadius = 5 + pulseVal * 2;
  var coreGrad = ctx.createRadialGradient(g.px, g.py, 0, g.px, g.py, coreRadius);
  coreGrad.addColorStop(0, 'rgba(180,255,230,0.95)');
  coreGrad.addColorStop(0.3, 'rgba(0,255,170,0.7)');
  coreGrad.addColorStop(1, 'rgba(0,255,170,0)');

  ctx.beginPath();
  ctx.arc(g.px, g.py, coreRadius, 0, Math.PI * 2);
  ctx.fillStyle = coreGrad;
  ctx.fill();

  // Sparkle rays — thin lines radiating outward
  var rayCount = 6;
  var rayOffset = glow.pulse * 0.4;
  ctx.save();
  ctx.globalAlpha = 0.15 + pulseVal * 0.1;
  ctx.strokeStyle = '#00ffaa';
  ctx.lineWidth = 0.5;
  for (var r = 0; r < rayCount; r++) {
    var angle = (r / rayCount) * Math.PI * 2 + rayOffset;
    var innerR = 3;
    var outerR = 12 + pulseVal * 6;
    ctx.beginPath();
    ctx.moveTo(g.px + Math.cos(angle) * innerR, g.py + Math.sin(angle) * innerR);
    ctx.lineTo(g.px + Math.cos(angle) * outerR, g.py + Math.sin(angle) * outerR);
    ctx.stroke();
  }
  ctx.restore();
})

registerModule('Floating Particle Spawner', function(g) {
  g._fps = g._fps || { pool: [], lastSpawn: 0 };
  var s = g._fps;
  var ctx = g.ctx;
  var W = g.canvas.width, H = g.canvas.height;

  if (g.tick - s.lastSpawn > 20 && s.pool.length < 60) {
    s.lastSpawn = g.tick;
    for (var n = 0; n < 2; n++) {
      var angle = Math.random() * Math.PI * 2;
      var dist = 100 + Math.random() * 250;
      var px = g.px + Math.cos(angle) * dist;
      var py = g.py + Math.sin(angle) * dist;
      px = ((px % W) + W) % W;
      py = ((py % H) + H) % H;
      var hue = Math.floor(g.rand(140, 300));
      s.pool.push({
        x: px, y: py,
        vx: g.rand(-0.4, 0.4), vy: g.rand(-0.4, 0.4),
        radius: g.rand(2, 5), hue: hue,
        pulse: g.rand(0, Math.PI * 2),
        pulseSpeed: g.rand(0.02, 0.06),
        score: Math.ceil(g.rand(1, 3))
      });
    }
  }

  var i = s.pool.length;
  while (i--) {
    var p = s.pool[i];
    p.pulse += p.pulseSpeed;
    p.x += p.vx + Math.sin(p.pulse * 0.7) * 0.3;
    p.y += p.vy + Math.cos(p.pulse) * 0.3;

    // Gentle drift toward center
    var dx = W/2 - p.x, dy = H/2 - p.y;
    var dc = Math.sqrt(dx*dx + dy*dy);
    if (dc > 50) { p.vx += (dx/dc) * 0.002; p.vy += (dy/dc) * 0.002; }

    // Clamp speed
    var spd = Math.sqrt(p.vx*p.vx + p.vy*p.vy);
    if (spd > 1) { p.vx = (p.vx/spd); p.vy = (p.vy/spd); }

    // Absorption check
    var adx = g.px - p.x, ady = g.py - p.y;
    var ad = Math.sqrt(adx*adx + ady*ady);
    if (ad < 10 + p.radius) {
      g.score += p.score * 10;
      g.absorbed = (g.absorbed || 0) + 1;
      // Burst particles
      for (var b = 0; b < 4; b++) {
        var ba = g.rand(0, Math.PI*2);
        g.particles.push({
          x: p.x, y: p.y,
          vx: Math.cos(ba) * g.rand(1,3), vy: Math.sin(ba) * g.rand(1,3),
          life: 1.0, decay: g.rand(0.04, 0.08),
          radius: g.rand(1, 3),
          color: 'hsl(' + p.hue + ',80%,70%)'
        });
      }
      s.pool.splice(i, 1);
      continue;
    }

    // Remove if way off screen
    if (p.x < -80 || p.x > W+80 || p.y < -80 || p.y > H+80) {
      s.pool.splice(i, 1); continue;
    }

    // Draw glow
    var r = Math.max(0.5, p.radius + Math.sin(p.pulse) * 1.2);
    var alpha = 0.6 + 0.3 * Math.sin(p.pulse);
    ctx.save();
    ctx.globalAlpha = alpha * 0.3;
    var grad = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, r * 3);
    grad.addColorStop(0, 'hsl(' + p.hue + ',80%,70%)');
    grad.addColorStop(1, 'hsla(' + p.hue + ',80%,70%,0)');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(p.x, p.y, r * 3, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.fillStyle = 'hsl(' + p.hue + ',80%,70%)';
    ctx.shadowColor = 'hsl(' + p.hue + ',80%,70%)';
    ctx.shadowBlur = 8;
    ctx.beginPath();
    ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }

  // Draw shared burst particles
  var j = g.particles.length;
  while (j--) {
    var pt = g.particles[j];
    if (!pt.decay) continue;
    pt.x += pt.vx; pt.y += pt.vy;
    pt.vx *= 0.92; pt.vy *= 0.92;
    pt.life -= pt.decay;
    if (pt.life <= 0) { g.particles.splice(j, 1); continue; }
    ctx.save();
    ctx.globalAlpha = pt.life * 0.8;
    ctx.fillStyle = pt.color;
    ctx.beginPath();
    ctx.arc(pt.x, pt.y, Math.max(0.5, pt.radius * pt.life), 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
});

registerModule('Score HUD', function(g) {
  var ctx = g.ctx;
  ctx.save();
  ctx.fillStyle = '#00ffaa';
  ctx.font = '14px Courier New';
  ctx.textAlign = 'left';
  ctx.globalAlpha = 0.8;
  ctx.fillText('Score: ' + g.score, 16, 28);
  ctx.fillText('Absorbed: ' + (g.absorbed || 0), 16, 46);
  if (g.stage > 0) ctx.fillText('Stage: ' + g.stage, 16, 64);
  ctx.restore();
});

registerModule('Score HUD', function(g) {
  g._hud = g._hud || { pulse: 0, lastScore: 0, flashTimer: 0 };

  var h = g._hud;
  var ctx = g.ctx;

  // Detect score change for flash effect
  if (g.score !== h.lastScore) {
    h.flashTimer = 18;
    h.lastScore = g.score;
  }
  if (h.flashTimer > 0) h.flashTimer--;

  h.pulse = (h.pulse + 0.05) % (Math.PI * 2);

  var pulseAlpha = 0.7 + 0.3 * Math.sin(h.pulse);
  var flashBoost = h.flashTimer > 0 ? (h.flashTimer / 18) : 0;

  var stageColors = ['#00ffaa', '#44ffcc', '#88ffdd', '#aaffee', '#ccffff', '#ffffff'];
  var stageColor = stageColors[Math.min(g.stage, stageColors.length - 1)];

  ctx.save();

  // --- Score Panel ---
  var panelX = 16;
  var panelY = 16;
  var panelW = 180;
  var panelH = 64;
  var cornerR = 8;

  // Panel background
  ctx.beginPath();
  ctx.moveTo(panelX + cornerR, panelY);
  ctx.lineTo(panelX + panelW - cornerR, panelY);
  ctx.quadraticCurveTo(panelX + panelW, panelY, panelX + panelW, panelY + cornerR);
  ctx.lineTo(panelX + panelW, panelY + panelH - cornerR);
  ctx.quadraticCurveTo(panelX + panelW, panelY + panelH, panelX + panelW - cornerR, panelY + panelH);
  ctx.lineTo(panelX + cornerR, panelY + panelH);
  ctx.quadraticCurveTo(panelX, panelY + panelH, panelX, panelY + panelH - cornerR);
  ctx.lineTo(panelX, panelY + cornerR);
  ctx.quadraticCurveTo(panelX, panelY, panelX + cornerR, panelY);
  ctx.closePath();
  ctx.fillStyle = 'rgba(4, 6, 15, 0.75)';
  ctx.fill();

  // Panel border glow
  var borderAlpha = (0.4 + 0.4 * flashBoost) * pulseAlpha;
  ctx.strokeStyle = 'rgba(' + (flashBoost > 0 ? '255,220,80' : '0,255,170') + ',' + borderAlpha + ')';
  ctx.lineWidth = 1.5 + flashBoost * 2;
  ctx.stroke();

  // SCORE label
  ctx.font = '10px monospace';
  ctx.letterSpacing = '2px';
  ctx.fillStyle = 'rgba(0,255,170,0.5)';
  ctx.fillText('SCORE', panelX + 14, panelY + 18);

  // Score value
  var scoreStr = String(g.score);
  var scoreFontSize = scoreStr.length > 7 ? 18 : 22;
  ctx.font = 'bold ' + scoreFontSize + 'px monospace';
  ctx.fillStyle = flashBoost > 0
    ? 'rgba(255,' + Math.floor(200 + 55 * flashBoost) + ',80,' + pulseAlpha + ')'
    : (stageColor);
  if (flashBoost > 0) {
    ctx.shadowColor = 'rgba(255,220,80,0.9)';
    ctx.shadowBlur = 12 * flashBoost;
  } else {
    ctx.shadowColor = stageColor;
    ctx.shadowBlur = 6 * pulseAlpha;
  }
  ctx.fillText(scoreStr, panelX + 14, panelY + 48);

  ctx.shadowBlur = 0;

  // --- Absorbed Panel ---
  var ap = { x: panelX, y: panelY + panelH + 8, w: panelW, h: 40 };

  ctx.beginPath();
  ctx.moveTo(ap.x + cornerR, ap.y);
  ctx.lineTo(ap.x + ap.w - cornerR, ap.y);
  ctx.quadraticCurveTo(ap.x + ap.w, ap.y, ap.x + ap.w, ap.y + cornerR);
  ctx.lineTo(ap.x + ap.w, ap.y + ap.h - cornerR);
  ctx.quadraticCurveTo(ap.x + ap.w, ap.y + ap.h, ap.x + ap.w - cornerR, ap.y + ap.h);
  ctx.lineTo(ap.x + cornerR, ap.y + ap.h);
  ctx.quadraticCurveTo(ap.x, ap.y + ap.h, ap.x, ap.y + ap.h - cornerR);
  ctx.lineTo(ap.x, ap.y + cornerR);
  ctx.quadraticCurveTo(ap.x, ap.y, ap.x + cornerR, ap.y);
  ctx.closePath();
  ctx.fillStyle = 'rgba(4, 6, 15, 0.65)';
  ctx.fill();
  ctx.strokeStyle = 'rgba(0,200,140,0.25)';
  ctx.lineWidth = 1;
  ctx.stroke();

  // Absorbed label
  ctx.font = '10px monospace';
  ctx.letterSpacing = '2px';
  ctx.fillStyle = 'rgba(0,200,140,0.45)';
  ctx.fillText('ABSORBED', ap.x + 14, ap.y + 16);

  // Absorbed count
  ctx.font = 'bold 16px monospace';
  ctx.fillStyle = 'rgba(0,220,160,0.85)';
  ctx.shadowColor = 'rgba(0,255,170,0.4)';
  ctx.shadowBlur = 4;
  ctx.fillText(String(g.absorbed || 0), ap.x + 14, ap.y + 32);
  ctx.shadowBlur = 0;

  // --- Stage Indicator ---
  var si = { x: panelX, y: ap.y + ap.h + 8 };
  ctx.font = '10px monospace';
  ctx.letterSpacing = '2px';
  ctx.fillStyle = 'rgba(0,200,140,0.4)';
  ctx.fillText('STAGE', si.x + 14, si.y + 12);

  var dotSpacing = 22;
  for (var i = 0; i <= 5; i++) {
    var dx = si.x + 14 + i * dotSpacing;
    var dy = si.y + 26;
    var filled = i <= g.stage;
    ctx.beginPath();
    ctx.arc(dx, dy, filled ? 6 : 4, 0, Math.PI * 2);
    if (filled) {
      ctx.fillStyle = stageColor;
      ctx.shadowColor = stageColor;
      ctx.shadowBlur = 8;
    } else {
      ctx.fillStyle = 'rgba(0,80,60,0.5)';
      ctx.shadowBlur = 0;
    }
    ctx.fill();
    ctx.shadowBlur = 0;
  }

  ctx.restore();
})

registerModule('Background Grid', function(g) {
  g._grid = g._grid || {
    offsetX: 0,
    offsetY: 0,
    prevPx: g.px,
    prevPy: g.py,
    pulse: 0
  };

  var grid = g._grid;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;

  // Track camera scroll from player movement
  var dx = g.px - grid.prevPx;
  var dy = g.py - grid.prevPy;
  grid.prevPx = g.px;
  grid.prevPy = g.py;

  grid.offsetX = (grid.offsetX - dx * 0.4) % 60;
  grid.offsetY = (grid.offsetY - dy * 0.4) % 60;

  // Pulse based on player speed
  var speed = Math.sqrt(g.vx * g.vx + g.vy * g.vy);
  grid.pulse = grid.pulse + (speed * 0.04 - grid.pulse) * 0.08;

  var cellSize = 60;
  var alpha = 0.045 + grid.pulse * 0.12;
  var glowAlpha = 0.018 + grid.pulse * 0.06;

  // Draw subtle glow lines first (wider, very transparent)
  ctx.save();
  ctx.lineWidth = 3;

  var startX = (grid.offsetX % cellSize + cellSize) % cellSize - cellSize;
  var startY = (grid.offsetY % cellSize + cellSize) % cellSize - cellSize;

  // Glow pass
  ctx.strokeStyle = 'rgba(0, 255, 170, ' + glowAlpha + ')';
  ctx.beginPath();
  for (var x = startX; x <= W + cellSize; x += cellSize) {
    ctx.moveTo(x, 0);
    ctx.lineTo(x, H);
  }
  for (var y = startY; y <= H + cellSize; y += cellSize) {
    ctx.moveTo(0, y);
    ctx.lineTo(W, y);
  }
  ctx.stroke();

  // Sharp pass
  ctx.lineWidth = 0.5;
  ctx.strokeStyle = 'rgba(0, 200, 140, ' + alpha + ')';
  ctx.beginPath();
  for (var x2 = startX; x2 <= W + cellSize; x2 += cellSize) {
    ctx.moveTo(x2, 0);
    ctx.lineTo(x2, H);
  }
  for (var y2 = startY; y2 <= H + cellSize; y2 += cellSize) {
    ctx.moveTo(0, y2);
    ctx.lineTo(W, y2);
  }
  ctx.stroke();

  // Draw intersection dots that pulse with movement
  var dotAlpha = 0.06 + grid.pulse * 0.2;
  var dotSize = 1 + grid.pulse * 1.5;
  ctx.fillStyle = 'rgba(0, 255, 170, ' + dotAlpha + ')';
  for (var xi = startX; xi <= W + cellSize; xi += cellSize) {
    for (var yi = startY; yi <= H + cellSize; yi += cellSize) {
      ctx.beginPath();
      ctx.arc(xi, yi, dotSize, 0, 6.2832);
      ctx.fill();
    }
  }

  ctx.restore();
})

registerModule('Adaptive Difficulty', function(g) {
  g._diff = g._diff || {
    tier: 0,
    lastTier: -1,
    flashTimer: 0,
    flashX: 0,
    flashY: 0,
    label: ''
  };

  var d = g._diff;
  var ctx = g.ctx;

  // Calculate tier from score, capped at 10
  var newTier = Math.min(10, Math.floor(g.score / 50));

  if (newTier !== d.tier) {
    d.lastTier = d.tier;
    d.tier = newTier;
    if (newTier > d.lastTier) {
      d.flashTimer = 120;
      d.flashX = g.canvas.width / 2;
      d.flashY = g.canvas.height / 2 - 60;
      d.label = newTier === 10 ? 'MAX DIFFICULTY!' : 'DIFFICULTY UP! TIER ' + newTier;
      // Burst particles on tier up
      for (var b = 0; b < 24; b++) {
        var angle = (b / 24) * Math.PI * 2;
        var spd = g.rand(1.5, 4.5);
        var hue = Math.floor(g.lerp(120, 0, newTier / 10));
        g.particles.push({
          x: g.px,
          y: g.py,
          vx: Math.cos(angle) * spd,
          vy: Math.sin(angle) * spd,
          life: 1,
          decay: g.rand(0.012, 0.025),
          size: g.rand(2, 5),
          color: 'hsl(' + hue + ',100%,65%)'
        });
      }
    }
  }

  // Expose difficulty multipliers for other modules
  g.diffTier    = d.tier;
  g.diffSpawn   = 1 + d.tier * 0.18;   // spawn rate multiplier
  g.diffSpeed   = 1 + d.tier * 0.12;   // enemy speed multiplier
  g.diffHP      = 1 + d.tier * 0.25;   // enemy HP multiplier

  // Draw tier indicator (top-right corner)
  var tierFrac = d.tier / 10;
  var barW = 120;
  var barH = 10;
  var bx = g.canvas.width - barW - 16;
  var by = 20;

  // Background bar
  ctx.save();
  ctx.globalAlpha = 0.55;
  ctx.fillStyle = '#111a2a';
  ctx.beginPath();
  ctx.roundRect ? ctx.roundRect(bx - 4, by - 18, barW + 8, barH + 28, 6)
                : ctx.rect(bx - 4, by - 18, barW + 8, barH + 28);
  ctx.fill();
  ctx.globalAlpha = 1;

  // Label
  ctx.font = 'bold 11px monospace';
  ctx.textAlign = 'left';
  var labelHue = Math.floor(g.lerp(160, 0, tierFrac));
  ctx.fillStyle = 'hsl(' + labelHue + ',100%,70%)';
  ctx.fillText('DIFFICULTY  T' + d.tier + '/10', bx, by - 4);

  // Filled bar segments
  var segW = (barW - 9 * 2) / 10;
  for (var i = 0; i < 10; i++) {
    var segX = bx + i * (segW + 2);
    var filled = i < d.tier;
    var active = i === d.tier - 1;
    var segHue = Math.floor(g.lerp(160, 0, i / 9));
    if (filled) {
      var pulse = active ? 0.75 + 0.25 * Math.sin(g.tick * 0.15) : 1;
      ctx.globalAlpha = pulse;
      ctx.fillStyle = 'hsl(' + segHue + ',100%,55%)';
      ctx.fillRect(segX, by, segW, barH);
      // Shine
      ctx.globalAlpha = 0.35 * pulse;
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(segX, by, segW, barH * 0.4);
    } else {
      ctx.globalAlpha = 0.18;
      ctx.fillStyle = '#445566';
      ctx.fillRect(segX, by, segW, barH);
    }
    ctx.globalAlpha = 1;
  }

  // Tier-up flash announcement
  if (d.flashTimer > 0) {
    var t = d.flashTimer / 120;
    var scale = 1 + 0.4 * Math.sin(t * Math.PI);
    var alpha = t < 0.2 ? t / 0.2 : (t > 0.7 ? (t - 0.7) / 0.3 : 1);
    alpha = Math.min(1, alpha);
    var fHue = Math.floor(g.lerp(0, 120, 1 - d.tier / 10));

    ctx.globalAlpha = alpha * 0.92;
    ctx.save();
    ctx.translate(d.flashX, d.flashY);
    ctx.scale(scale, scale);
    ctx.textAlign = 'center';

    // Glow
    ctx.shadowColor = 'hsl(' + fHue + ',100%,60%)';
    ctx.shadowBlur = 24;
    ctx.font = 'bold 28px monospace';
    ctx.fillStyle = 'hsl(' + fHue + ',100%,72%)';
    ctx.fillText(d.label, 0, 0);

    // Sub text
    ctx.shadowBlur = 0;
    ctx.font = '13px monospace';
    ctx.fillStyle = '#aaddff';
    ctx.fillText(
      'spd x' + g.diffSpeed.toFixed(2) +
      '  hp x' + g.diffHP.toFixed(2) +
      '  spawn x' + g.diffSpawn.toFixed(2),
      0, 22
    );
    ctx.restore();
    ctx.globalAlpha = 1;

    d.flashTimer--;
  }

  // Screen tint intensifies with tier (subtle vignette)
  if (d.tier > 0) {
    var vigAlpha = 0.04 + tierFrac * 0.09;
    var vig = ctx.createRadialGradient(
      g.canvas.width / 2, g.canvas.height / 2, g.canvas.height * 0.3,
      g.canvas.width / 2, g.canvas.height / 2, g.canvas.height * 0.85
    );
    var vigHue = Math.floor(g.lerp(200, 0, tierFrac));
    vig.addColorStop(0, 'rgba(0,0,0,0)');
    vig.addColorStop(1, 'hsla(' + vigHue + ',90%,20%,' + vigAlpha + ')');
    ctx.fillStyle = vig;
    ctx.fillRect(0, 0, g.canvas.width, g.canvas.height);
  }

  ctx.restore();
  ctx.textAlign = 'left';
  ctx.shadowBlur = 0;
})

registerModule('Screen Shake VFX', function(g) {
  g._shake = g._shake || {
    intensity: 0,
    duration: 0,
    offsetX: 0,
    offsetY: 0,
    lastAbsorbed: 0,
    lastScore: 0,
    trauma: 0
  };

  var s = g._shake;
  var ctx = g.ctx;

  // Detect absorption events (enemy collision)
  var absorbed = g.absorbed || 0;
  var score = g.score || 0;

  if (absorbed > s.lastAbsorbed) {
    var delta = absorbed - s.lastAbsorbed;
    // Add trauma (trauma-based shake for natural feel)
    s.trauma = Math.min(1.0, s.trauma + 0.35 * delta);
    s.lastAbsorbed = absorbed;
  }

  // Also shake on score milestones
  if (score > s.lastScore) {
    var scoreDelta = score - s.lastScore;
    if (scoreDelta >= 10) {
      s.trauma = Math.min(1.0, s.trauma + 0.15);
    }
    s.lastScore = score;
  }

  // Stage-up detection
  var prevStage = s.prevStage || 0;
  if (g.stage > prevStage) {
    s.trauma = Math.min(1.0, s.trauma + 0.7);
  }
  s.prevStage = g.stage;

  // Decay trauma over time
  s.trauma = Math.max(0, s.trauma - 0.018);

  // Calculate shake from trauma (squared for more punchy feel)
  var shakeAmt = s.trauma * s.trauma;
  var maxShakeX = 18;
  var maxShakeY = 14;

  // Use noise-like shake using tick for variation
  var t = g.tick;
  var angle1 = t * 0.37 + Math.sin(t * 0.73) * 2.1;
  var angle2 = t * 0.53 + Math.cos(t * 0.61) * 1.8;

  s.offsetX = Math.sin(angle1) * shakeAmt * maxShakeX;
  s.offsetY = Math.cos(angle2) * shakeAmt * maxShakeY;

  // Apply shake by translating canvas context
  if (shakeAmt > 0.001) {
    ctx.save();
    ctx.translate(s.offsetX, s.offsetY);

    // Vignette effect during shake — darkens edges
    var vigAlpha = shakeAmt * 0.55;
    var vW = g.canvas.width;
    var vH = g.canvas.height;
    var grad = ctx.createRadialGradient(
      vW / 2, vH / 2, vH * 0.25,
      vW / 2, vH / 2, vH * 0.85
    );
    grad.addColorStop(0, 'rgba(0,0,0,0)');
    grad.addColorStop(1, 'rgba(180,0,30,' + vigAlpha.toFixed(3) + ')');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, vW, vH);

    // Chromatic aberration flash lines during heavy shake
    if (shakeAmt > 0.3 && (t % 3 === 0)) {
      var lineCount = Math.floor(shakeAmt * 5);
      for (var i = 0; i < lineCount; i++) {
        var ly = g.rand(0, vH);
        var lw = g.rand(vW * 0.3, vW);
        var lx = g.rand(0, vW - lw);
        var lh = g.rand(1, 3);
        ctx.fillStyle = 'rgba(255,' + Math.floor(g.rand(0,80)) + ',' + Math.floor(g.rand(0,60)) + ',0.12)';
        ctx.fillRect(lx, ly, lw, lh);
      }
    }

    ctx.restore();

    // Expose shake offset so other modules can optionally use it
    g._shakeOffsetX = s.offsetX;
    g._shakeOffsetY = s.offsetY;
  } else {
    g._shakeOffsetX = 0;
    g._shakeOffsetY = 0;
  }

  // Debug indicator (tiny trauma bar, subtle)
  if (s.trauma > 0.01) {
    var barW = 60;
    var barH = 3;
    var bx = g.canvas.width - barW - 12;
    var by = 12;
    ctx.fillStyle = 'rgba(0,0,0,0.5)';
    ctx.fillRect(bx, by, barW, barH);
    var traumaColor = s.trauma > 0.6 ? '#ff2244' : s.trauma > 0.3 ? '#ff8800' : '#ffdd00';
    ctx.fillStyle = traumaColor;
    ctx.fillRect(bx, by, barW * s.trauma, barH);
  }
})

registerModule('Score Streak', function(g) {
  g._streak = g._streak || {
    count: 0,
    lastAbsorb: 0,
    prevAbsorbed: 0,
    floaters: [],
    flashTimer: 0,
    bestStreak: 0
  };

  var s = g._streak;
  var ctx = g.ctx;
  var now = g.tick;
  var WINDOW = 120; // 2 seconds at 60fps

  // Detect new absorption
  if (g.absorbed > s.prevAbsorbed) {
    var timeSinceLast = now - s.lastAbsorb;

    if (s.lastAbsorb > 0 && timeSinceLast <= WINDOW) {
      s.count += 1;
    } else {
      s.count = 1;
    }

    s.lastAbsorb = now;
    s.prevAbsorbed = g.absorbed;

    if (s.count > s.bestStreak) s.bestStreak = s.count;

    // Apply score multiplier (add bonus points proportional to multiplier)
    if (s.count >= 2) {
      var bonus = (s.count - 1) * 5;
      g.score = (g.score || 0) + bonus;
    }

    s.flashTimer = 20;

    // Spawn floating multiplier text
    if (s.count >= 2) {
      s.floaters.push({
        x: g.px + g.rand(-10, 10),
        y: g.py - 10,
        vy: -1.8 - g.rand(0, 0.8),
        vx: g.rand(-0.4, 0.4),
        life: 70,
        maxLife: 70,
        count: s.count,
        scale: 1 + (s.count - 2) * 0.12
      });
    }
  }

  // Reset streak after idle window
  if (s.lastAbsorb > 0 && (now - s.lastAbsorb) > WINDOW) {
    s.count = 0;
    s.lastAbsorb = 0;
  }

  // Expose multiplier globally for other modules
  g.streakMultiplier = s.count >= 2 ? s.count : 1;
  g.streakCount = s.count;

  // Draw streak indicator near player
  if (s.count >= 2) {
    var alpha = 1.0;
    var pulse = 1 + 0.15 * Math.sin(now * 0.3);
    var hue = (now * 3 + s.count * 40) % 360;

    ctx.save();
    ctx.globalAlpha = alpha;

    // Glow ring around player
    var glowRadius = (14 + s.count * 3) * pulse;
    var grad = ctx.createRadialGradient(g.px, g.py, 2, g.px, g.py, glowRadius);
    grad.addColorStop(0, 'hsla(' + hue + ',100%,70%,0.35)');
    grad.addColorStop(1, 'hsla(' + hue + ',100%,50%,0)');
    ctx.beginPath();
    ctx.arc(g.px, g.py, glowRadius, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();

    // Streak label
    ctx.font = 'bold ' + Math.floor((13 + s.count) * pulse) + 'px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    var label = 'x' + s.count;
    var lx = g.px;
    var ly = g.py - 22 - s.count * 2;

    // Shadow
    ctx.shadowColor = 'hsl(' + hue + ',100%,60%)';
    ctx.shadowBlur = 8 + s.count * 2;
    ctx.fillStyle = 'hsl(' + hue + ',100%,75%)';
    ctx.fillText(label, lx, ly);

    // Outer ring arcs spinning
    var numArcs = Math.min(s.count, 6);
    var arcR = 18 + s.count * 2;
    for (var i = 0; i < numArcs; i++) {
      var angle = (now * 0.04 + (Math.PI * 2 * i / numArcs));
      var arcH = (hue + i * 40) % 360;
      ctx.beginPath();
      ctx.arc(g.px, g.py, arcR, angle, angle + 0.45);
      ctx.strokeStyle = 'hsla(' + arcH + ',100%,70%,0.8)';
      ctx.lineWidth = 2;
      ctx.shadowBlur = 4;
      ctx.shadowColor = 'hsla(' + arcH + ',100%,60%,1)';
      ctx.stroke();
    }

    ctx.restore();
  }

  // Update and draw floating multiplier texts
  for (var j = s.floaters.length - 1; j >= 0; j--) {
    var f = s.floaters[j];
    f.x += f.vx;
    f.y += f.vy;
    f.vy *= 0.97;
    f.life--;

    if (f.life <= 0) {
      s.floaters.splice(j, 1);
      continue;
    }

    var t = f.life / f.maxLife;
    var fadeAlpha = t < 0.3 ? (t / 0.3) : 1.0;
    var fhue = ((f.count * 45) + 160) % 360;
    var fscale = f.scale * (1 + (1 - t) * 0.3);
    var fontSize = Math.floor(14 * fscale + f.count * 2);

    ctx.save();
    ctx.globalAlpha = fadeAlpha * 0.95;
    ctx.font = 'bold ' + fontSize + 'px monospace';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.shadowColor = 'hsl(' + fhue + ',100%,65%)';
    ctx.shadowBlur = 10;
    ctx.fillStyle = 'hsl(' + fhue + ',100%,80%)';
    ctx.fillText('x' + f.count + '!', f.x, f.y);
    ctx.restore();
  }

  // Flash on new absorption
  if (s.flashTimer > 0) {
    s.flashTimer--;
    var fp = s.flashTimer / 20;
    ctx.save();
    ctx.globalAlpha = fp * 0.18;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, g.canvas.width, g.canvas.height);
    ctx.restore();
  }
})

registerModule('Minimap Radar', function(g) {
  g._radar = g._radar || { initialized: true };

  var ctx = g.ctx;
  var cw = g.canvas.width;
  var ch = g.canvas.height;

  var radius = 70;
  var cx = cw - radius - 18;
  var cy = ch - radius - 18;
  var radarRange = 320;

  // Draw radar background
  ctx.save();

  // Outer glow ring
  var glowGrad = ctx.createRadialGradient(cx, cy, radius - 4, cx, cy, radius + 6);
  glowGrad.addColorStop(0, 'rgba(0,255,170,0.25)');
  glowGrad.addColorStop(1, 'rgba(0,255,170,0)');
  ctx.beginPath();
  ctx.arc(cx, cy, radius + 6, 0, Math.PI * 2);
  ctx.fillStyle = glowGrad;
  ctx.fill();

  // Radar background fill
  ctx.beginPath();
  ctx.arc(cx, cy, radius, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(2, 8, 20, 0.72)';
  ctx.fill();

  // Concentric range rings
  ctx.strokeStyle = 'rgba(0,255,170,0.12)';
  ctx.lineWidth = 1;
  for (var r = 1; r <= 3; r++) {
    ctx.beginPath();
    ctx.arc(cx, cy, (radius / 3) * r, 0, Math.PI * 2);
    ctx.stroke();
  }

  // Crosshair lines
  ctx.strokeStyle = 'rgba(0,255,170,0.18)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(cx - radius, cy);
  ctx.lineTo(cx + radius, cy);
  ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(cx, cy - radius);
  ctx.lineTo(cx, cy + radius);
  ctx.stroke();

  // Sweep line animation
  var sweepAngle = (g.tick * 0.035) % (Math.PI * 2);
  var sweepGrad = ctx.createConicalGradient
    ? null
    : null; // fallback to manual arc

  ctx.save();
  ctx.beginPath();
  ctx.moveTo(cx, cy);
  ctx.arc(cx, cy, radius, sweepAngle - 0.9, sweepAngle, false);
  ctx.closePath();
  ctx.fillStyle = 'rgba(0,255,170,0.13)';
  ctx.fill();

  ctx.beginPath();
  ctx.moveTo(cx, cy);
  ctx.lineTo(
    cx + Math.cos(sweepAngle) * radius,
    cy + Math.sin(sweepAngle) * radius
  );
  ctx.strokeStyle = 'rgba(0,255,170,0.7)';
  ctx.lineWidth = 1.5;
  ctx.stroke();
  ctx.restore();

  // Clip all dots inside radar circle
  ctx.save();
  ctx.beginPath();
  ctx.arc(cx, cy, radius - 2, 0, Math.PI * 2);
  ctx.clip();

  // Draw particles as green dots
  if (g.particles) {
    for (var i = 0; i < g.particles.length; i++) {
      var p = g.particles[i];
      if (!p) continue;
      var dx = p.x - g.px;
      var dy = p.y - g.py;
      var dist = Math.sqrt(dx * dx + dy * dy);
      if (dist > radarRange) continue;
      var mx = cx + (dx / radarRange) * radius;
      var my = cy + (dy / radarRange) * radius;
      ctx.beginPath();
      ctx.arc(mx, my, 1.5, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(0,255,100,0.8)';
      ctx.fill();
    }
  }

  // Draw entities — enemies red, power-ups gold
  if (g.entities) {
    for (var j = 0; j < g.entities.length; j++) {
      var e = g.entities[j];
      if (!e) continue;
      var ex = e.x - g.px;
      var ey = e.y - g.py;
      var edist = Math.sqrt(ex * ex + ey * ey);
      if (edist > radarRange) continue;
      var emx = cx + (ex / radarRange) * radius;
      var emy = cy + (ey / radarRange) * radius;

      var dotColor;
      var dotSize;
      if (e.type === 'powerup' || e.isPowerup) {
        dotColor = 'rgba(255,210,50,0.95)';
        dotSize = 2.5;
      } else {
        dotColor = 'rgba(255,60,60,0.92)';
        dotSize = 2;
      }

      // Pulse for nearby threats
      if (edist < radarRange * 0.3 && e.type !== 'powerup' && !e.isPowerup) {
        var pulse = 0.5 + 0.5 * Math.sin(g.tick * 0.18 + j);
        ctx.beginPath();
        ctx.arc(emx, emy, dotSize + 2.5 * pulse, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(255,60,60,' + (0.15 * pulse) + ')';
        ctx.fill();
      }

      ctx.beginPath();
      ctx.arc(emx, emy, dotSize, 0, Math.PI * 2);
      ctx.fillStyle = dotColor;
      ctx.fill();
    }
  }

  ctx.restore(); // restore clip

  // Player center dot
  ctx.beginPath();
  ctx.arc(cx, cy, 3, 0, Math.PI * 2);
  ctx.fillStyle = '#00ffaa';
  ctx.fill();
  ctx.beginPath();
  ctx.arc(cx, cy, 5, 0, Math.PI * 2);
  ctx.strokeStyle = 'rgba(0,255,170,0.5)';
  ctx.lineWidth = 1.5;
  ctx.stroke();

  // Outer border ring
  ctx.beginPath();
  ctx.arc(cx, cy, radius, 0, Math.PI * 2);
  ctx.strokeStyle = 'rgba(0,255,170,0.55)';
  ctx.lineWidth = 2;
  ctx.stroke();

  // Label
  ctx.fillStyle = 'rgba(0,255,170,0.45)';
  ctx.font = '9px monospace';
  ctx.textAlign = 'center';
  ctx.fillText('RADAR', cx, cy + radius + 12);

  ctx.restore();
})

registerModule('Mini-Map Corner Navigation Indicator', function(g) {
  g._miniMap = g._miniMap || {
    trail: [],
    maxTrail: 40,
    lastTick: -1
  };

  var mm = g._miniMap;
  var ctx = g.ctx;

  var MAP_SIZE = 64;
  var MAP_PAD = 10;
  var MAP_X = g.canvas.width - MAP_SIZE - MAP_PAD;
  var MAP_Y = 50;
  var WORLD_W = g.canvas.width;
  var WORLD_H = g.canvas.height;
  var SCALE_X = MAP_SIZE / WORLD_W;
  var SCALE_Y = MAP_SIZE / WORLD_H;

  MAP_X = g.canvas.width - MAP_SIZE - MAP_PAD;

  // Record trail every 4 ticks
  if (g.tick !== mm.lastTick && g.tick % 4 === 0) {
    mm.lastTick = g.tick;
    mm.trail.push({ x: g.px, y: g.py });
    if (mm.trail.length > mm.maxTrail) {
      mm.trail.shift();
    }
  }

  ctx.save();

  // Outer glow border
  ctx.shadowColor = '#00ffaa';
  ctx.shadowBlur = 8;
  ctx.strokeStyle = 'rgba(0, 255, 170, 0.5)';
  ctx.lineWidth = 1;
  ctx.strokeRect(MAP_X - 1, MAP_Y - 1, MAP_SIZE + 2, MAP_SIZE + 2);
  ctx.shadowBlur = 0;

  // Background
  ctx.fillStyle = 'rgba(4, 6, 15, 0.85)';
  ctx.fillRect(MAP_X, MAP_Y, MAP_SIZE, MAP_SIZE);

  // Clip to mini-map area
  ctx.beginPath();
  ctx.rect(MAP_X, MAP_Y, MAP_SIZE, MAP_SIZE);
  ctx.clip();

  // Subtle grid lines inside mini-map
  ctx.strokeStyle = 'rgba(0, 255, 170, 0.06)';
  ctx.lineWidth = 0.5;
  var gridStep = MAP_SIZE / 4;
  for (var gx = 0; gx <= 4; gx++) {
    ctx.beginPath();
    ctx.moveTo(MAP_X + gx * gridStep, MAP_Y);
    ctx.lineTo(MAP_X + gx * gridStep, MAP_Y + MAP_SIZE);
    ctx.stroke();
  }
  for (var gy = 0; gy <= 4; gy++) {
    ctx.beginPath();
    ctx.moveTo(MAP_X, MAP_Y + gy * gridStep);
    ctx.lineTo(MAP_X + MAP_SIZE, MAP_Y + gy * gridStep);
    ctx.stroke();
  }

  // Boundary corner markers
  ctx.strokeStyle = 'rgba(0, 255, 170, 0.35)';
  ctx.lineWidth = 1;
  var cornerLen = 5;
  // top-left
  ctx.beginPath(); ctx.moveTo(MAP_X, MAP_Y + cornerLen); ctx.lineTo(MAP_X, MAP_Y); ctx.lineTo(MAP_X + cornerLen, MAP_Y); ctx.stroke();
  // top-right
  ctx.beginPath(); ctx.moveTo(MAP_X + MAP_SIZE - cornerLen, MAP_Y); ctx.lineTo(MAP_X + MAP_SIZE, MAP_Y); ctx.lineTo(MAP_X + MAP_SIZE, MAP_Y + cornerLen); ctx.stroke();
  // bottom-left
  ctx.beginPath(); ctx.moveTo(MAP_X, MAP_Y + MAP_SIZE - cornerLen); ctx.lineTo(MAP_X, MAP_Y + MAP_SIZE); ctx.lineTo(MAP_X + cornerLen, MAP_Y + MAP_SIZE); ctx.stroke();
  // bottom-right
  ctx.beginPath(); ctx.moveTo(MAP_X + MAP_SIZE - cornerLen, MAP_Y + MAP_SIZE); ctx.lineTo(MAP_X + MAP_SIZE, MAP_Y + MAP_SIZE); ctx.lineTo(MAP_X + MAP_SIZE, MAP_Y + MAP_SIZE - cornerLen); ctx.stroke();

  // Draw trail
  for (var i = 0; i < mm.trail.length; i++) {
    var t = mm.trail[i];
    var alpha = (i / mm.trail.length) * 0.55;
    var tx = MAP_X + t.x * SCALE_X;
    var ty = MAP_Y + t.y * SCALE_Y;
    var radius = 0.8 + (i / mm.trail.length) * 0.8;
    ctx.beginPath();
    ctx.arc(tx, ty, radius, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(0, 255, 170, ' + alpha + ')';
    ctx.fill();
  }

  // Player dot with pulse
  var pulse = 0.6 + 0.4 * Math.sin(g.tick * 0.15);
  var pdx = MAP_X + g.px * SCALE_X;
  var pdy = MAP_Y + g.py * SCALE_Y;

  // Outer glow ring
  ctx.beginPath();
  ctx.arc(pdx, pdy, 3.5 * pulse, 0, Math.PI * 2);
  ctx.fillStyle = 'rgba(0, 255, 170, 0.15)';
  ctx.fill();

  // Inner bright dot
  ctx.shadowColor = '#00ffaa';
  ctx.shadowBlur = 6;
  ctx.beginPath();
  ctx.arc(pdx, pdy, 2, 0, Math.PI * 2);
  ctx.fillStyle = '#00ffaa';
  ctx.fill();
  ctx.shadowBlur = 0;

  ctx.restore();

  // Label
  ctx.save();
  ctx.font = '7px monospace';
  ctx.fillStyle = 'rgba(0, 255, 170, 0.45)';
  ctx.textAlign = 'right';
  ctx.fillText('MAP', MAP_X + MAP_SIZE, MAP_Y + MAP_SIZE + 9);
  ctx.restore();
})

registerModule('Background Nebula', function(g) {
  g._nebula = g._nebula || (function() {
    var clouds = [];
    var count = 18;
    for (var i = 0; i < count; i++) {
      clouds.push({
        x: Math.random() * 1600 - 400,
        y: Math.random() * 1200 - 300,
        r: 80 + Math.random() * 180,
        hue: Math.random() * 360,
        hueSpeed: (Math.random() - 0.5) * 0.18,
        sat: 60 + Math.random() * 40,
        alpha: 0.04 + Math.random() * 0.07,
        px: 0.08 + Math.random() * 0.18,
        py: 0.06 + Math.random() * 0.16,
        wobbleX: Math.random() * Math.PI * 2,
        wobbleY: Math.random() * Math.PI * 2,
        wobbleSpeedX: 0.0008 + Math.random() * 0.001,
        wobbleSpeedY: 0.0006 + Math.random() * 0.001,
        wobbleAmp: 18 + Math.random() * 40
      });
    }
    return { clouds: clouds, offscreen: null, dirty: true };
  }());

  var state = g._nebula;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;

  // Update hues and wobble
  for (var i = 0; i < state.clouds.length; i++) {
    var c = state.clouds[i];
    c.hue += c.hueSpeed;
    if (c.hue > 360) c.hue -= 360;
    if (c.hue < 0) c.hue += 360;
    c.wobbleX += c.wobbleSpeedX;
    c.wobbleY += c.wobbleSpeedY;
  }

  // Draw nebula clouds directly to main canvas, below everything else
  // We save/restore to not disturb other modules
  ctx.save();

  for (var i = 0; i < state.clouds.length; i++) {
    var c = state.clouds[i];

    // Parallax offset based on player position relative to canvas center
    var offX = (g.px - W * 0.5) * c.px;
    var offY = (g.py - H * 0.5) * c.py;

    // Wobble motion
    var wx = Math.sin(c.wobbleX) * c.wobbleAmp;
    var wy = Math.cos(c.wobbleY) * c.wobbleAmp;

    var cx = c.x + wx - offX;
    var cy = c.y + wy - offY;

    // Cull if way off screen
    if (cx + c.r < -60 || cx - c.r > W + 60 || cy + c.r < -60 || cy - c.r > H + 60) continue;

    // Radial gradient for soft cloud look
    var grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, c.r);
    var h1 = c.hue;
    var h2 = (c.hue + 40) % 360;
    var h3 = (c.hue + 80) % 360;

    grad.addColorStop(0,   'hsla(' + h1 + ',' + c.sat + '%,70%,' + (c.alpha * 1.4) + ')');
    grad.addColorStop(0.4, 'hsla(' + h2 + ',' + c.sat + '%,55%,' + (c.alpha * 0.9) + ')');
    grad.addColorStop(0.75,'hsla(' + h3 + ',' + c.sat + '%,40%,' + (c.alpha * 0.4) + ')');
    grad.addColorStop(1,   'hsla(' + h1 + ',30%,20%,0)');

    ctx.globalCompositeOperation = 'screen';
    ctx.globalAlpha = 1;
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(cx, cy, c.r, 0, Math.PI * 2);
    ctx.fill();

    // Second inner glow pass for richness
    var innerR = c.r * 0.45;
    var grad2 = ctx.createRadialGradient(cx, cy, 0, cx, cy, innerR);
    grad2.addColorStop(0,   'hsla(' + h2 + ',' + (c.sat + 20) + '%,90%,' + (c.alpha * 0.8) + ')');
    grad2.addColorStop(0.5, 'hsla(' + h3 + ',' + c.sat + '%,60%,' + (c.alpha * 0.3) + ')');
    grad2.addColorStop(1,   'hsla(' + h1 + ',20%,30%,0)');

    ctx.fillStyle = grad2;
    ctx.beginPath();
    ctx.arc(cx, cy, innerR, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.globalCompositeOperation = 'source-over';
  ctx.globalAlpha = 1;
  ctx.restore();
})

registerModule('Orbit Particles', function(g) {
  g._orbit = g._orbit || { particles: [] };

  var orbit = g._orbit;
  var ctx = g.ctx;
  var stage = g.stage || 0;

  // Target count scales with stage
  var targetCount = 3 + stage * 2;
  var baseRadius = 18 + stage * 8;

  // Add particles if needed
  while (orbit.particles.length < targetCount) {
    var idx = orbit.particles.length;
    orbit.particles.push({
      angle: (idx / targetCount) * Math.PI * 2,
      speed: g.rand(0.03, 0.07) * (Math.random() < 0.5 ? 1 : -1),
      radius: baseRadius + g.rand(-4, 4),
      size: g.rand(1.5, 3.5),
      hue: Math.floor(g.rand(0, 360)),
      layer: Math.floor(g.rand(0, 2)) // 0 = inner, 1 = outer
    });
  }

  // Remove excess particles smoothly
  if (orbit.particles.length > targetCount) {
    orbit.particles.length = targetCount;
  }

  // Update radii to match current stage
  for (var i = 0; i < orbit.particles.length; i++) {
    var p = orbit.particles[i];

    // Smoothly adjust radius toward target
    var targetR = (p.layer === 0 ? baseRadius * 0.7 : baseRadius) + p.radius % 5;
    p.radius = g.lerp(p.radius, baseRadius + (p.layer === 0 ? -6 : 6), 0.02);

    // Orbit speed varies slightly with stage
    p.angle += p.speed * (1 + stage * 0.05);

    // Compute position
    var wobble = Math.sin(g.tick * 0.04 + i * 1.3) * 2;
    var rx = Math.cos(p.angle) * (p.radius + wobble);
    var ry = Math.sin(p.angle) * (p.radius + wobble) * 0.7; // slight ellipse

    var px = g.px + rx;
    var py = g.py + ry;

    // Color cycles with stage and time
    var hue = (p.hue + g.tick * 0.5) % 360;
    var alpha = 0.6 + Math.sin(g.tick * 0.07 + i) * 0.3;
    var size = p.size * (0.8 + stage * 0.1);

    // Glow effect: draw larger faded circle first
    ctx.beginPath();
    ctx.arc(px, py, size * 2.2, 0, Math.PI * 2);
    ctx.fillStyle = 'hsla(' + hue + ', 100%, 70%, ' + (alpha * 0.25) + ')';
    ctx.fill();

    // Core dot
    ctx.beginPath();
    ctx.arc(px, py, size, 0, Math.PI * 2);
    ctx.fillStyle = 'hsla(' + hue + ', 100%, 80%, ' + alpha + ')';
    ctx.fill();

    // Tiny trailing arc behind each particle
    ctx.beginPath();
    var trailAngle = p.speed > 0 ? p.angle - 0.35 : p.angle + 0.35;
    ctx.arc(
      g.px, g.py,
      p.radius + wobble,
      trailAngle,
      p.angle,
      p.speed < 0
    );
    ctx.strokeStyle = 'hsla(' + hue + ', 100%, 65%, 0.18)';
    ctx.lineWidth = size * 0.9;
    ctx.stroke();
  }
})

registerModule('Combo Chain System', function(g) {
  g._combo = g._combo || {
    actions: [],
    lastAbsorbed: 0,
    lastDash: 0,
    displayCombos: [],
    prevAbsorbed: 0,
    prevSpeed: 0,
    dashCooldown: 0,
    wasDashing: false
  };

  var c = g._combo;
  var ctx = g.ctx;

  // Detect absorb action
  var justAbsorbed = (g.absorbed > c.prevAbsorbed);
  if (justAbsorbed) {
    c.actions.push({ type: 'absorb', t: g.tick });
    if (c.actions.length > 5) c.actions.shift();
    c.prevAbsorbed = g.absorbed;
  }

  // Detect dash action (speed spike via keys + velocity magnitude)
  var spd = Math.sqrt(g.vx * g.vx + g.vy * g.vy);
  var isDashing = spd > g.speed * 1.6;
  if (isDashing && !c.wasDashing && g.tick - c.dashCooldown > 30) {
    c.actions.push({ type: 'dash', t: g.tick });
    if (c.actions.length > 5) c.actions.shift();
    c.dashCooldown = g.tick;
  }
  c.wasDashing = isDashing;
  c.prevSpeed = spd;

  // Purge stale actions older than 3 seconds
  var now = g.tick;
  for (var i = c.actions.length - 1; i >= 0; i--) {
    if (now - c.actions[i].t > 180) {
      c.actions.splice(i, 1);
    }
  }

  // Combo detection on each new action
  if (justAbsorbed || isDashing) {
    var seq = '';
    for (var j = 0; j < c.actions.length; j++) {
      seq += c.actions[j].type === 'absorb' ? 'A' : 'D';
    }

    var combo = null;

    // Check patterns (longest first)
    if (seq.slice(-5) === 'AAADA' || seq.slice(-5) === 'ADAAA') {
      combo = { name: 'RAMPAGE HARVEST', bonus: 400, color: '#ff2200' };
    } else if (seq.slice(-4) === 'ADAA') {
      combo = { name: 'DASH HARVEST', bonus: 200, color: '#ff9900' };
    } else if (seq.slice(-4) === 'AADA') {
      combo = { name: 'SCATTER RUSH', bonus: 180, color: '#ff6600' };
    } else if (seq.slice(-4) === 'DADA') {
      combo = { name: 'ZIGZAG FRENZY', bonus: 250, color: '#cc44ff' };
    } else if (seq.slice(-4) === 'DAAA') {
      combo = { name: 'BLITZ ABSORB', bonus: 220, color: '#ff44cc' };
    } else if (seq.slice(-3) === 'ADA') {
      combo = { name: 'DASH SNATCH', bonus: 150, color: '#ffcc00' };
    } else if (seq.slice(-3) === 'DAD') {
      combo = { name: 'DRIFT COMBO', bonus: 130, color: '#44ffcc' };
    } else if (seq.slice(-3) === 'AAA') {
      combo = { name: 'TRIPLE ABSORB', bonus: 150, color: '#00ffaa' };
    } else if (seq.slice(-2) === 'DA') {
      combo = { name: 'DASH GRAB', bonus: 80, color: '#88ffff' };
    } else if (seq.slice(-2) === 'AA') {
      combo = { name: 'DOUBLE ABSORB', bonus: 60, color: '#44ff88' };
    }

    if (combo && justAbsorbed) {
      g.score = (g.score || 0) + combo.bonus;
      c.displayCombos.push({
        name: combo.name,
        bonus: combo.bonus,
        color: combo.color,
        x: g.px + g.rand(-60, 60),
        y: g.py - 40,
        vy: -1.2,
        life: 120,
        maxLife: 120,
        scale: 1.4
      });
      if (c.displayCombos.length > 6) c.displayCombos.shift();
    }
  }

  // Render combo displays
  for (var k = c.displayCombos.length - 1; k >= 0; k--) {
    var d = c.displayCombos[k];
    d.y += d.vy;
    d.vy *= 0.97;
    d.life--;

    if (d.life <= 0) {
      c.displayCombos.splice(k, 1);
      continue;
    }

    var alpha = d.life / d.maxLife;
    var easeIn = d.life > d.maxLife * 0.8 ? (1 - d.life / d.maxLife) * 5 : 1;
    var finalAlpha = alpha * Math.min(easeIn, 1);
    var pulse = 1 + 0.08 * Math.sin(g.tick * 0.3 + k);
    var sc = d.scale * pulse * Math.min(easeIn * 1.5, 1);

    ctx.save();
    ctx.translate(d.x, d.y);
    ctx.scale(sc, sc);
    ctx.globalAlpha = finalAlpha;

    // Glow shadow
    ctx.shadowBlur = 18;
    ctx.shadowColor = d.color;

    // Combo name
    ctx.font = 'bold 15px monospace';
    ctx.textAlign = 'center';
    ctx.fillStyle = '#ffffff';
    ctx.fillText(d.name, 0, 0);

    // Bonus score
    ctx.font = 'bold 20px monospace';
    ctx.fillStyle = d.color;
    ctx.fillText('+' + d.bonus, 0, 22);

    // Underline bar
    var bw = 80 * (d.life / d.maxLife);
    ctx.fillStyle = d.color;
    ctx.globalAlpha = finalAlpha * 0.6;
    ctx.fillRect(-bw / 2, 28, bw, 2);

    ctx.restore();
  }

  // Action indicator — show last 5 action dots near player
  if (c.actions.length > 0) {
    var dotX = g.px - (c.actions.length * 10) / 2;
    var dotY = g.py + 20;
    for (var m = 0; m < c.actions.length; m++) {
      var act = c.actions[m];
      var age = (now - act.t) / 180;
      var dotAlpha = 1 - age * 0.6;
      ctx.save();
      ctx.globalAlpha = dotAlpha * 0.85;
      ctx.shadowBlur = 8;
      ctx.shadowColor = act.type === 'absorb' ? '#00ffaa' : '#ff9900';
      ctx.beginPath();
      ctx.arc(dotX + m * 10, dotY, 3.5, 0, Math.PI * 2);
      ctx.fillStyle = act.type === 'absorb' ? '#00ffaa' : '#ff9900';
      ctx.fill();
      ctx.restore();
    }
  }
})

registerModule('Pixel Trail Effect on Mouse Movement', function(g) {
  g._mouseTrail = g._mouseTrail || {
    particles: [],
    mouseX: g.canvas.width / 2,
    mouseY: g.canvas.height / 2,
    lastX: g.canvas.width / 2,
    lastY: g.canvas.height / 2,
    lastSpawn: 0
  };

  var mt = g._mouseTrail;
  var ctx = g.ctx;

  // Track mouse position
  if (!mt._listenerAttached) {
    mt._listenerAttached = true;
    mt._onMouseMove = function(e) {
      var rect = g.canvas.getBoundingClientRect();
      mt.mouseX = e.clientX - rect.left;
      mt.mouseY = e.clientY - rect.top;
    };
    window.addEventListener('mousemove', mt._onMouseMove);
  }

  var now = g.tick;
  var dx = mt.mouseX - mt.lastX;
  var dy = mt.mouseY - mt.lastY;
  var moveDist = Math.sqrt(dx * dx + dy * dy);

  // Spawn particles along mouse path when moving
  var spawnInterval = g.stage <= 1 ? 2 : 3;
  if (moveDist > 1.5 && (now - mt.lastSpawn) >= spawnInterval) {
    mt.lastSpawn = now;

    var steps = Math.min(Math.floor(moveDist / 4), 5);
    for (var s = 0; s <= steps; s++) {
      var t = steps > 0 ? s / steps : 0;
      var spawnX = mt.lastX + dx * t;
      var spawnY = mt.lastY + dy * t;

      // High contrast colors matching 1-bit aesthetic
      var colorRoll = (now + s * 37) % 6;
      var color;
      if (colorRoll === 0) color = '#ffffff';
      else if (colorRoll === 1) color = '#00ffaa';
      else if (colorRoll === 2) color = '#ffffff';
      else if (colorRoll === 3) color = '#aaffee';
      else if (colorRoll === 4) color = '#00ffcc';
      else color = '#ffffff';

      var size = g.stage <= 1 ? 2 : (g.stage <= 3 ? 3 : 2);

      mt.particles.push({
        x: spawnX + (Math.random() - 0.5) * 3,
        y: spawnY + (Math.random() - 0.5) * 3,
        size: size,
        color: color,
        born: now,
        life: 30, // 0.5 seconds at 60fps
        vx: (Math.random() - 0.5) * 0.6,
        vy: (Math.random() - 0.5) * 0.6
      });
    }

    mt.lastX = mt.mouseX;
    mt.lastY = mt.mouseY;
  } else if (moveDist <= 1.5) {
    mt.lastX = mt.mouseX;
    mt.lastY = mt.mouseY;
  }

  // Update and draw particles
  var i = mt.particles.length - 1;
  while (i >= 0) {
    var p = mt.particles[i];
    var age = now - p.born;

    if (age >= p.life) {
      mt.particles.splice(i, 1);
      i--;
      continue;
    }

    var progress = age / p.life;
    var alpha = 1.0 - progress;
    // Sharp fade: stay bright then drop off
    alpha = alpha * alpha * (3 - 2 * alpha); // smoothstep invert
    alpha = Math.max(0, Math.min(1, alpha));

    // Drift outward slightly
    p.x += p.vx;
    p.y += p.vy;

    // Pixel-perfect square rendering
    var sz = Math.max(1, Math.floor(p.size * (1.0 - progress * 0.4)));

    ctx.globalAlpha = alpha;
    ctx.fillStyle = p.color;

    // Snap to pixel grid for 1-bit aesthetic
    var px = Math.floor(p.x - sz / 2);
    var py = Math.floor(p.y - sz / 2);
    ctx.fillRect(px, py, sz, sz);

    // Occasional inverted shadow for contrast on light backgrounds
    if (sz >= 2 && alpha > 0.6) {
      ctx.globalAlpha = alpha * 0.25;
      ctx.fillStyle = '#04060f';
      ctx.fillRect(px + 1, py + 1, sz, sz);
    }

    i--;
  }

  ctx.globalAlpha = 1.0;
})

registerModule('Pixel Trail Effect for Mouse Movement', function(g) {
  g._mouseTrail = g._mouseTrail || {
    mx: 0,
    my: 0,
    lastMx: 0,
    lastMy: 0,
    ready: false
  };

  var mt = g._mouseTrail;

  if (!mt.ready) {
    mt.ready = true;
    mt.onMove = function(e) {
      var rect = g.canvas.getBoundingClientRect();
      mt.mx = e.clientX - rect.left;
      mt.my = e.clientY - rect.top;
    };
    g.canvas.addEventListener('mousemove', mt.onMove);
  }

  var dx = mt.mx - mt.lastMx;
  var dy = mt.my - mt.lastMy;
  var moveDist = Math.sqrt(dx * dx + dy * dy);

  if (moveDist > 2) {
    var score = g.score || 0;
    var stage = g.stage || 0;

    var spawnCount = Math.min(3 + stage, 6);
    var steps = Math.ceil(moveDist / 6);
    steps = Math.min(steps, spawnCount);

    for (var s = 0; s < steps; s++) {
      var t = steps <= 1 ? 1 : s / (steps - 1);
      var sx = mt.lastMx + (mt.mx - mt.lastMx) * t;
      var sy = mt.lastMy + (mt.my - mt.lastMy) * t;

      var hue, sat, lit;
      if (stage === 0) {
        hue = 180;
        sat = 10;
        lit = 95;
      } else if (stage === 1) {
        hue = 180;
        sat = 60;
        lit = 85;
      } else if (stage === 2) {
        hue = 185 + Math.sin(g.tick * 0.05) * 15;
        sat = 80;
        lit = 75;
      } else if (stage === 3) {
        hue = 190 + Math.sin(g.tick * 0.08) * 40;
        sat = 90;
        lit = 70;
      } else if (stage === 4) {
        hue = 280 + Math.sin(g.tick * 0.1) * 80;
        sat = 95;
        lit = 65;
      } else {
        hue = (g.tick * 3 + s * 40) % 360;
        sat = 100;
        lit = 60;
      }

      var colorStr = 'hsl(' + hue + ',' + sat + '%,' + lit + '%)';

      var speed = 0.3 + Math.random() * 0.5;
      var angle = Math.random() * Math.PI * 2;

      g.particles.push({
        x: sx + (Math.random() - 0.5) * 4,
        y: sy + (Math.random() - 0.5) * 4,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed - 0.2,
        life: 1.0,
        decay: 0.033 + Math.random() * 0.02,
        size: 1 + Math.random() * (1 + stage * 0.4),
        color: colorStr,
        isMouse: true
      });
    }

    mt.lastMx = mt.mx;
    mt.lastMy = mt.my;
  }

  var ctx = g.ctx;
  for (var i = g.particles.length - 1; i >= 0; i--) {
    var p = g.particles[i];
    if (!p.isMouse) continue;

    p.x += p.vx;
    p.y += p.vy;
    p.life -= p.decay;

    if (p.life <= 0) {
      g.particles.splice(i, 1);
      continue;
    }

    var alpha = p.life * p.life;
    var sz = p.size * p.life;

    ctx.save();
    ctx.globalAlpha = alpha * 0.85;
    ctx.fillStyle = p.color;

    if (sz > 1.5) {
      ctx.shadowColor = p.color;
      ctx.shadowBlur = 4 + (g.stage || 0);
    }

    ctx.fillRect(
      Math.round(p.x - sz * 0.5),
      Math.round(p.y - sz * 0.5),
      Math.ceil(sz),
      Math.ceil(sz)
    );
    ctx.restore();
  }
})

registerModule('Pixel Collision Ripple Wave', function(g) {
  g._ripple = g._ripple || { waves: [], lastAbsorbed: 0, lastParticleCount: 0 };

  var R = g._ripple;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;

  // Detect collision events
  var absorbed = g.absorbed || 0;
  var triggered = false;
  var impactX = g.px;
  var impactY = g.py;

  if (absorbed !== R.lastAbsorbed) {
    triggered = true;
    R.lastAbsorbed = absorbed;
  }

  // Also check for nearby particle collisions
  if (!triggered && g.particles) {
    for (var i = 0; i < g.particles.length; i++) {
      var p = g.particles[i];
      if (!p) continue;
      var dx = p.x - g.px;
      var dy = p.y - g.py;
      var d = dx * dx + dy * dy;
      if (d < 400) {
        triggered = true;
        impactX = (p.x + g.px) * 0.5;
        impactY = (p.y + g.py) * 0.5;
        break;
      }
    }
  }

  // Spawn new ripple wave on collision
  if (triggered && (g.tick - (R.lastSpawnTick || 0)) > 6) {
    R.lastSpawnTick = g.tick;
    var stage = g.stage || 0;
    var hue = 120 + stage * 40;
    R.waves.push({
      x: impactX,
      y: impactY,
      age: 0,
      maxAge: (stage > 2 ? 36 : 28),
      rings: 3 + stage,
      hue: hue,
      speed: 2.5 + stage * 0.4,
      intensity: 0.7 + stage * 0.06
    });
    if (R.waves.length > 18) R.waves.splice(0, R.waves.length - 18);
  }

  // Draw and update ripple waves
  ctx.save();
  for (var w = R.waves.length - 1; w >= 0; w--) {
    var wave = R.waves[w];
    wave.age++;
    var t = wave.age / wave.maxAge;
    if (t >= 1) { R.waves.splice(w, 1); continue; }

    var easeOut = 1 - t * t;
    var baseAlpha = easeOut * wave.intensity;

    for (var r = 0; r < wave.rings; r++) {
      var ringOffset = r / wave.rings;
      var ringT = Math.max(0, t - ringOffset * 0.3);
      if (ringT <= 0) continue;

      var radius = ringT * wave.maxAge * wave.speed * (1 - ringOffset * 0.25);
      var ringAlpha = baseAlpha * (1 - ringT) * (1 - ringOffset * 0.4);
      if (ringAlpha <= 0.01) continue;

      var sat = 70 + ringOffset * 20;
      var lit = 55 + ringOffset * 15;
      var pixelCount = Math.floor(8 + radius * 0.55 + r * 4);
      var angleStep = (Math.PI * 2) / pixelCount;
      var pixSize = Math.max(1, 2.5 - ringOffset * 0.8 - t * 1.2);

      ctx.fillStyle = 'hsla(' + (wave.hue + ringOffset * 30) + ',' + sat + '%,' + lit + '%,' + ringAlpha + ')';

      for (var j = 0; j < pixelCount; j++) {
        var angle = j * angleStep + wave.age * 0.04 * (r % 2 === 0 ? 1 : -1);
        var wobble = 1 + Math.sin(wave.age * 0.3 + j * 0.7 + r) * 0.08;
        var rx = wave.x + Math.cos(angle) * radius * wobble;
        var ry = wave.y + Math.sin(angle) * radius * wobble;
        ctx.fillRect(rx - pixSize * 0.5, ry - pixSize * 0.5, pixSize, pixSize);
      }
    }

    // Central burst flash
    if (wave.age < 6) {
      var flashT = 1 - wave.age / 6;
      var flashSize = flashT * 12 * (1 + (g.stage || 0) * 0.3);
      ctx.fillStyle = 'hsla(' + wave.hue + ',100%,85%,' + (flashT * 0.85) + ')';
      ctx.fillRect(wave.x - flashSize * 0.5, wave.y - flashSize * 0.5, flashSize, flashSize);
    }
  }
  ctx.restore();
})

registerModule('Pixel Bloom Pulse', function(g) {
  g._bloomPulse = g._bloomPulse || {
    blooms: [],
    lastMilestone: 0
  };

  var state = g._bloomPulse;
  var ctx = g.ctx;

  // Check for new score milestone
  var currentMilestone = Math.floor(g.score / 500);
  if (currentMilestone > state.lastMilestone && g.score > 0) {
    state.lastMilestone = currentMilestone;
    // Spawn a new bloom at player position
    state.blooms.push({
      x: g.px,
      y: g.py,
      age: 0,
      maxAge: 80,
      milestone: currentMilestone,
      rings: 8
    });
  }

  // Draw and update blooms
  for (var i = state.blooms.length - 1; i >= 0; i--) {
    var bloom = state.blooms[i];
    bloom.age++;

    if (bloom.age >= bloom.maxAge) {
      state.blooms.splice(i, 1);
      continue;
    }

    var progress = bloom.age / bloom.maxAge;
    var eased = 1 - Math.pow(1 - progress, 3); // ease out cubic

    ctx.save();

    for (var r = 0; r < bloom.rings; r++) {
      var ringProgress = (r / bloom.rings);
      // Each ring starts slightly delayed
      var ringAge = (bloom.age - ringProgress * 20) / (bloom.maxAge - ringProgress * 20);
      if (ringAge <= 0) continue;
      if (ringAge > 1) ringAge = 1;

      var ringEased = 1 - Math.pow(1 - ringAge, 2);
      var size = ringEased * (200 + r * 40);
      var alpha = (1 - ringAge) * (1 - ringProgress * 0.4) * 0.85;

      if (alpha <= 0) continue;

      // Color: white to accent color (#00ffaa)
      var whiteMix = Math.pow(1 - ringAge, 2);
      var red   = Math.round(255 * whiteMix + 0 * (1 - whiteMix));
      var green = Math.round(255 * whiteMix + 255 * (1 - whiteMix));
      var blue  = Math.round(255 * whiteMix + 170 * (1 - whiteMix));

      ctx.strokeStyle = 'rgba(' + red + ',' + green + ',' + blue + ',' + alpha + ')';
      ctx.lineWidth = Math.max(1, 3 - ringProgress * 2);
      ctx.shadowColor = 'rgba(' + red + ',' + green + ',' + blue + ',' + (alpha * 0.6) + ')';
      ctx.shadowBlur = 8 + whiteMix * 12;

      // Draw concentric square ring
      var half = size / 2;
      ctx.strokeRect(
        bloom.x - half,
        bloom.y - half,
        size,
        size
      );

      // 8 cardinal pixel bursts
      var burstLen = size * 0.18 * (1 - ringAge);
      var dirs = [
        [0, -1], [0, 1], [-1, 0], [1, 0],
        [-0.707, -0.707], [0.707, -0.707],
        [-0.707, 0.707], [0.707, 0.707]
      ];

      ctx.lineWidth = Math.max(1, 2 - ringProgress);
      for (var d = 0; d < 8; d++) {
        var dx = dirs[d][0];
        var dy = dirs[d][1];
        var startDist = size * 0.5 + 2;
        var endDist = startDist + burstLen;

        ctx.beginPath();
        ctx.moveTo(bloom.x + dx * startDist, bloom.y + dy * startDist);
        ctx.lineTo(bloom.x + dx * endDist, bloom.y + dy * endDist);
        ctx.stroke();
      }
    }

    // Central flash on first frames
    if (bloom.age < 12) {
      var flashAlpha = (1 - bloom.age / 12) * 0.9;
      var flashSize = bloom.age * 5;
      ctx.fillStyle = 'rgba(255,255,255,' + flashAlpha + ')';
      ctx.shadowColor = 'rgba(0,255,170,' + flashAlpha + ')';
      ctx.shadowBlur = 20;
      ctx.fillRect(
        bloom.x - flashSize / 2,
        bloom.y - flashSize / 2,
        flashSize,
        flashSize
      );
    }

    // Milestone number burst text
    if (bloom.age < 40) {
      var textAlpha = (1 - bloom.age / 40) * 0.95;
      var textY = bloom.y - 30 - eased * 30;
      ctx.globalAlpha = textAlpha;
      ctx.font = 'bold ' + Math.round(14 + eased * 8) + 'px monospace';
      ctx.fillStyle = '#00ffaa';
      ctx.shadowColor = '#00ffaa';
      ctx.shadowBlur = 10;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('' + (bloom.milestone * 500), bloom.x, textY);
      ctx.globalAlpha = 1;
    }

    ctx.restore();
  }
})

registerModule('Pixel Dust Collision Impact Feedback', function(g) {
  g._dustSystem = g._dustSystem || {
    particles: [],
    lastAbsorbed: 0,
    lastScore: 0,
    lastPx: 0,
    lastPy: 0
  };

  var ds = g._dustSystem;
  var ctx = g.ctx;
  var tick = g.tick;

  // Detect collision events via score change or absorbed count change
  var absorbed = g.absorbed || 0;
  var collisionDetected = false;
  var impactX = g.px;
  var impactY = g.py;
  var impactColor = '#ffffff';

  if (absorbed !== ds.lastAbsorbed) {
    collisionDetected = true;
    ds.lastAbsorbed = absorbed;

    // Pick color based on stage or absorbed parity for variety
    var stage = g.stage || 0;
    var colorOptions = [
      '#00ffaa', '#ff6644', '#ffdd00', '#44aaff',
      '#ff44cc', '#88ff44', '#ff8833', '#44ffee'
    ];
    impactColor = colorOptions[(absorbed + stage) % colorOptions.length];
  }

  if (collisionDetected) {
    // Direction of travel at impact moment
    var vx = g.vx || 0;
    var vy = g.vy || 0;
    var speed = Math.sqrt(vx * vx + vy * vy) || 1;
    var nx = vx / speed;
    var ny = vy / speed;

    var count = Math.floor(g.rand(4, 9));

    for (var i = 0; i < count; i++) {
      // Spread angle: mostly forward with fan spread
      var spreadAngle = (Math.random() - 0.5) * Math.PI * 1.4;
      var cos = Math.cos(spreadAngle);
      var sin = Math.sin(spreadAngle);
      // Rotate direction vector
      var dvx = nx * cos - ny * sin;
      var dvy = nx * sin + ny * cos;

      var particleSpeed = g.rand(1.2, 4.5);
      var size = g.rand(1.5, 3.5);

      ds.particles.push({
        x: impactX + g.rand(-3, 3),
        y: impactY + g.rand(-3, 3),
        vx: dvx * particleSpeed + g.rand(-0.5, 0.5),
        vy: dvy * particleSpeed + g.rand(-0.5, 0.5),
        color: impactColor,
        alpha: 1.0,
        size: size,
        decay: g.rand(0.025, 0.055), // per frame alpha decay (~300ms at 60fps)
        born: tick,
        trail: []
      });
    }
  }

  ds.lastPx = g.px;
  ds.lastPy = g.py;

  // Update and render dust particles
  var alive = [];
  for (var j = 0; j < ds.particles.length; j++) {
    var p = ds.particles[j];

    // Physics update
    p.x += p.vx;
    p.y += p.vy;
    p.vx *= 0.88;
    p.vy *= 0.88;
    p.alpha -= p.decay;

    if (p.alpha <= 0) continue;

    // Store trail point (limit trail length)
    p.trail.push({ x: p.x, y: p.y, alpha: p.alpha });
    if (p.trail.length > 5) p.trail.shift();

    // Draw trail
    for (var t = 0; t < p.trail.length; t++) {
      var tp = p.trail[t];
      var trailAlpha = tp.alpha * (t / p.trail.length) * 0.4;
      if (trailAlpha <= 0) continue;

      ctx.save();
      ctx.globalAlpha = trailAlpha;
      ctx.fillStyle = p.color;
      var ts = p.size * (t / p.trail.length) * 0.8;
      ctx.fillRect(
        Math.floor(tp.x - ts * 0.5),
        Math.floor(tp.y - ts * 0.5),
        Math.ceil(ts),
        Math.ceil(ts)
      );
      ctx.restore();
    }

    // Draw main particle as sharp square pixel
    ctx.save();
    ctx.globalAlpha = p.alpha;
    ctx.fillStyle = p.color;

    // Bright core highlight
    ctx.shadowColor = p.color;
    ctx.shadowBlur = p.alpha * 4;

    var ps = Math.ceil(p.size);
    ctx.fillRect(
      Math.floor(p.x - ps * 0.5),
      Math.floor(p.y - ps * 0.5),
      ps,
      ps
    );

    // Inner bright pixel
    ctx.globalAlpha = p.alpha * 0.7;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(
      Math.floor(p.x - 0.5),
      Math.floor(p.y - 0.5),
      1,
      1
    );

    ctx.restore();

    alive.push(p);
  }

  ds.particles = alive;
})

registerModule('Absorption Burst VFX', function(g) {
  g._absorptionBursts = g._absorptionBursts || { bursts: [], lastAbsorbed: 0 };

  var state = g._absorptionBursts;

  // Detect new absorptions by tracking absorbed count
  if (g.absorbed !== state.lastAbsorbed && g.absorbed > state.lastAbsorbed) {
    // Find recently absorbed entity color - scan entities for dying ones
    // Also trigger burst at player position with a plausible color
    var burstColor = '#00ffaa';

    // Try to get color from recently absorbed particles
    if (g._lastAbsorbedColor) {
      burstColor = g._lastAbsorbedColor;
    }

    var count = Math.floor(g.rand(5, 11));
    for (var i = 0; i < count; i++) {
      var angle = (i / count) * Math.PI * 2 + g.rand(-0.3, 0.3);
      var speed = g.rand(1.5, 4.5);
      state.bursts.push({
        x: g.px,
        y: g.py,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        life: 20,
        maxLife: 20,
        size: g.rand(2, 5),
        color: burstColor,
        alpha: 1
      });
    }

    // Central flash ring
    state.bursts.push({
      x: g.px,
      y: g.py,
      vx: 0,
      vy: 0,
      life: 12,
      maxLife: 12,
      size: g.rand(8, 14),
      color: burstColor,
      alpha: 0.6,
      ring: true
    });

    state.lastAbsorbed = g.absorbed;
  }

  var ctx = g.ctx;

  // Update and draw bursts
  for (var j = state.bursts.length - 1; j >= 0; j--) {
    var b = state.bursts[j];
    b.life--;

    if (b.life <= 0) {
      state.bursts.splice(j, 1);
      continue;
    }

    var t = b.life / b.maxLife;

    b.x += b.vx;
    b.y += b.vy;
    b.vx *= 0.88;
    b.vy *= 0.88;

    var currentSize = b.ring ? b.size * t : b.size * t;
    var currentAlpha = b.ring ? t * 0.7 : t;

    ctx.save();
    ctx.globalAlpha = currentAlpha;

    if (b.ring) {
      // Draw expanding ring
      ctx.strokeStyle = b.color;
      ctx.lineWidth = 1.5;
      ctx.shadowColor = b.color;
      ctx.shadowBlur = 8;
      ctx.beginPath();
      ctx.arc(b.x, b.y, currentSize * (1 - t) * 12 + 2, 0, Math.PI * 2);
      ctx.stroke();
    } else {
      // Draw particle with glow
      ctx.shadowColor = b.color;
      ctx.shadowBlur = 6 * t;
      ctx.fillStyle = b.color;
      ctx.beginPath();
      ctx.arc(b.x, b.y, Math.max(0.3, currentSize), 0, Math.PI * 2);
      ctx.fill();

      // Bright core
      ctx.shadowBlur = 2;
      ctx.fillStyle = '#ffffff';
      ctx.globalAlpha = currentAlpha * 0.6;
      ctx.beginPath();
      ctx.arc(b.x, b.y, Math.max(0.2, currentSize * 0.35), 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.restore();
  }
})

registerModule('Movement Trail', function(g) {
  g._trail = g._trail || { points: [], maxLen: 40 };

  var trail = g._trail;
  var ctx = g.ctx;
  var moving = g.vx !== 0 || g.vy !== 0;

  if (moving) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLen) {
      trail.points.shift();
    }
  }

  for (var i = 0; i < trail.points.length; i++) {
    trail.points[i].age++;
  }

  for (var j = 0; j < trail.points.length; j++) {
    var p = trail.points[j];
    var t = j / trail.points.length;
    var alpha = t * 0.7;
    var size = t * 3.5 + 0.5;
    var r = Math.floor(0 + (0) * t);
    var gv = Math.floor(200 + 55 * t);
    var b = Math.floor(100 + 70 * t);
    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.shadowColor = 'rgba(0,255,170,' + alpha + ')';
    ctx.shadowBlur = 6 * t;
    ctx.fillStyle = 'rgb(' + r + ',' + gv + ',' + b + ')';
    ctx.beginPath();
    ctx.arc(p.x, p.y, size, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }

  if (!moving && trail.points.length > 0) {
    trail.points.shift();
  }
})

registerModule('Ambient Starfield', function(g) {
  g._starfield = g._starfield || (function() {
    var stars = [];
    var count = 180;
    for (var i = 0; i < count; i++) {
      stars.push({
        x: Math.random() * 1600,
        y: Math.random() * 1200,
        z: Math.random() * 3 + 0.2,
        r: Math.random() * 1.4 + 0.2,
        twinkle: Math.random() * Math.PI * 2,
        twinkleSpeed: Math.random() * 0.04 + 0.008,
        color: Math.random() < 0.15 ? 1 : Math.random() < 0.1 ? 2 : 0
      });
    }
    return { stars: stars, initialized: true };
  })();

  var sf = g._starfield;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var stars = sf.stars;
  var px = g.px;
  var py = g.py;
  var tick = g.tick;

  ctx.save();

  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    // Parallax drift relative to player, layered by z
    var parallaxX = (px / W - 0.5) * s.z * 18;
    var parallaxY = (py / H - 0.5) * s.z * 18;

    // Slow autonomous drift
    s.x += s.z * 0.04;
    s.y += s.z * 0.015;

    // Wrap around canvas (with padding)
    if (s.x > W + 20) s.x = -20;
    if (s.y > H + 20) s.y = -20;
    if (s.x < -20) s.x = W + 20;
    if (s.y < -20) s.y = H + 20;

    // Twinkle
    s.twinkle += s.twinkleSpeed;
    var twinkleVal = 0.5 + 0.5 * Math.sin(s.twinkle);
    var alpha = (0.35 + 0.55 * twinkleVal) * Math.min(1, s.z / 1.2);

    var sx = s.x - parallaxX;
    var sy = s.y - parallaxY;
    var sr = s.r * (0.85 + 0.3 * twinkleVal);

    // Color variants
    var col;
    if (s.color === 1) {
      // Warm yellowish
      col = 'rgba(255,' + Math.floor(220 + 30 * twinkleVal) + ',140,' + alpha.toFixed(2) + ')';
    } else if (s.color === 2) {
      // Cool bluish
      col = 'rgba(140,190,' + Math.floor(230 + 25 * twinkleVal) + ',' + alpha.toFixed(2) + ')';
    } else {
      // Default white-blue
      var wb = Math.floor(200 + 55 * twinkleVal);
      col = 'rgba(' + wb + ',' + wb + ',255,' + alpha.toFixed(2) + ')';
    }

    ctx.beginPath();
    ctx.arc(sx, sy, sr, 0, Math.PI * 2);
    ctx.fillStyle = col;
    ctx.fill();

    // Add a subtle cross-sparkle for brighter stars
    if (s.r > 1.1 && twinkleVal > 0.7) {
      var sparkAlpha = (twinkleVal - 0.7) * alpha * 2.5;
      var sparkLen = sr * 3.5;
      ctx.strokeStyle = 'rgba(255,255,255,' + sparkAlpha.toFixed(2) + ')';
      ctx.lineWidth = 0.5;
      ctx.beginPath();
      ctx.moveTo(sx - sparkLen, sy);
      ctx.lineTo(sx + sparkLen, sy);
      ctx.moveTo(sx, sy - sparkLen);
      ctx.lineTo(sx, sy + sparkLen);
      ctx.stroke();
    }
  }

  ctx.restore();
})

registerModule('Movement Trail', function(g) {
  g._trail = g._trail || { points: [], maxLen: 40 };

  var trail = g._trail;
  var ctx = g.ctx;
  var moving = g.vx !== 0 || g.vy !== 0;

  if (moving) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLen) {
      trail.points.shift();
    }
  }

  for (var i = 0; i < trail.points.length; i++) {
    trail.points[i].age++;
  }

  var len = trail.points.length;
  for (var j = 0; j < len; j++) {
    var p = trail.points[j];
    var progress = j / (len - 1 || 1);
    var alpha = progress * 0.7 * (1 - p.age / 80);
    if (alpha <= 0) continue;

    var size = 1 + progress * 2.5;
    var r = Math.floor(g.lerp(0, 0, progress));
    var gr = Math.floor(g.lerp(180, 255, progress));
    var b = Math.floor(g.lerp(200, 170, progress));

    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.shadowColor = 'rgba(0,255,180,' + alpha + ')';
    ctx.shadowBlur = 6 * progress;
    ctx.fillStyle = 'rgb(' + r + ',' + gr + ',' + b + ')';
    ctx.beginPath();
    ctx.arc(p.x, p.y, size, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
})
